const body = $json.body || $json;
const source = body.source || 'Direct';
const leadId = 'LEAD-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);

const sanitizeString = (str) => {
  if (!str) return '';
  return String(str).trim().replace(/[<>"']/g, '');
};

const sanitizeEmail = (email) => {
  if (!email) return '';
  const e = String(email).toLowerCase().trim();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e) ? e : '';
};

const sanitizePhone = (phone) => {
  if (!phone) return '';
  return String(phone).replace(/\D/g, '').slice(-10) || '';
};

const leadData = {
  leadId: leadId,
  source: sanitizeString(source),
  firstName: sanitizeString(body.firstName || body.name?.split(' ')[0] || ''),
  lastName: sanitizeString(body.lastName || body.name?.split(' ')[1] || ''),
  fullName: sanitizeString(body.name || body.firstName + ' ' + body.lastName || ''),
  email: sanitizeEmail(body.email),
  phone: sanitizePhone(body.phone),
  company: sanitizeString(body.company || ''),
  jobTitle: sanitizeString(body.jobTitle || ''),
  industry: sanitizeString(body.industry || ''),
  service: sanitizeString(body.service || ''),
  budget: Math.max(0, Number(body.budget) || 0),
  currency: sanitizeString(body.currency || 'INR'),
  location: sanitizeString(body.location || ''),
  country: sanitizeString(body.country || ''),
  message: sanitizeString(body.message || ''),
  businessType: sanitizeString(body.businessType || ''),
  employeeCount: Math.max(0, Number(body.employeeCount) || 0),
  website: sanitizeString(body.website || ''),
  leadStatus: 'New Lead',
  leadScore: 0,
  leadCategory: 'Unqualified',
  priority: 'Normal',
  urgency: 'Normal',
  buyingIntent: 'Unknown',
  conversionProbability: '0%',
  assignedTo: 'Unassigned',
  qualificationStatus: 'Pending',
  pipelineStage: 'Lead Capture',
  dealValue: 0,
  followUpStatus: 'Pending',
  lastFollowUp: null,
  nextFollowUp: 'Day 1',
  createdAt: new Date().toISOString(),
  updatedAt: new Date().toISOString(),
  metadata: {
    userAgent: body.userAgent || '',
    ipAddress: body.ipAddress || '',
    utmSource: body.utmSource || '',
    utmMedium: body.utmMedium || '',
    utmCampaign: body.utmCampaign || ''
  }
};

if (!leadData.email && !leadData.phone) {
  throw new Error('Email or phone is required');
}

return { json: leadData };

const lead = $json;
let score = 0;

if (lead.budget >= 500000) score += 50;
else if (lead.budget >= 200000) score += 35;
else if (lead.budget >= 100000) score += 25;
else if (lead.budget >= 50000) score += 15;
else if (lead.budget > 0) score += 5;

const highValueServices = ['CRM Automation', 'AI Chatbot', 'Marketing Automation', 'Enterprise Solutions', 'Custom Development'];
if (highValueServices.includes(lead.service)) score += 20;
else if (lead.service) score += 10;

const premiumIndustries = ['Technology', 'Finance', 'Healthcare', 'E-commerce', 'SaaS', 'Enterprise'];
if (premiumIndustries.includes(lead.industry)) score += 15;
else if (lead.industry) score += 5;

const premiumBusinessTypes = ['Enterprise', 'SaaS', 'Agency', 'Startup', 'Corporate'];
if (premiumBusinessTypes.includes(lead.businessType)) score += 15;
else if (lead.businessType) score += 5;

const premiumCities = ['mumbai', 'bangalore', 'delhi', 'hyderabad', 'pune', 'new york', 'san francisco', 'london', 'toronto'];
if (premiumCities.includes((lead.location || '').toLowerCase())) score += 10;

const msg = (lead.message || '').toLowerCase();
const urgentKeywords = ['urgent', 'immediately', 'asap', 'today', 'tonight', 'emergency'];
const buyingKeywords = ['need', 'interested', 'buy', 'want', 'demo', 'call', 'meeting', 'proposal', 'pricing', 'quote', 'implement', 'start'];
const negativeKeywords = ['not sure', 'maybe', 'later', 'research', 'thinking', 'no time'];

urgentKeywords.forEach(kw => {
  if (msg.includes(kw)) score += 15;
});

buyingKeywords.forEach(kw => {
  if (msg.includes(kw)) score += 5;
});

negativeKeywords.forEach(kw => {
  if (msg.includes(kw)) score -= 5;
});

if (lead.employeeCount >= 500) score += 10;
else if (lead.employeeCount >= 100) score += 5;

if (lead.email && lead.email.match(/^[a-z0-9._%+-]+@(gmail|yahoo|outlook)\.com$/i)) score += 3;
if (lead.website) score += 5;

score = Math.min(100, Math.max(0, score));

let leadCategory = 'Cold Lead';
let priority = 'Low';
let urgency = 'Normal';
let buyingIntent = 'Low';

if (score >= 80) {
  leadCategory = 'Hot Lead';
  priority = 'High';
  buyingIntent = 'High';
  if (msg.includes('urgent') || msg.includes('immediately')) urgency = 'Critical';
  else urgency = 'High';
} else if (score >= 50) {
  leadCategory = 'Warm Lead';
  priority = 'Medium';
  buyingIntent = 'Medium';
  urgency = 'Normal';
} else if (score >= 30) {
  leadCategory = 'Cool Lead';
  priority = 'Low';
  buyingIntent = 'Low';
  urgency = 'Normal';
}

let assignedTo = 'General Sales Team';
if (lead.service === 'AI Chatbot') assignedTo = 'AI Sales Specialist';
else if (lead.service === 'CRM Automation') assignedTo = 'CRM Specialist';
else if (lead.service === 'Marketing Automation') assignedTo = 'Marketing Automation Expert';
else if (lead.service === 'Enterprise Solutions') assignedTo = 'Enterprise Sales Manager';
else if (score >= 80) assignedTo = 'Senior Sales Executive';
else if (score >= 50) assignedTo = 'Sales Executive';

let aiRecommendation = '';
if (score >= 80) {
  aiRecommendation = `🔥 HOT LEAD ALERT: High buying intent detected (Score: ${score}/100). Immediate action needed. Call within 2 hours. Budget: ${lead.currency} ${lead.budget}. Message indicates urgency.`;
} else if (score >= 50) {
  aiRecommendation = `✅ QUALIFIED LEAD: Good potential for conversion (Score: ${score}/100). Start nurture sequence. Schedule call within 24 hours.`;
} else if (score >= 30) {
  aiRecommendation = `📧 NURTURE LEAD: Potential prospect (Score: ${score}/100). Continue nurture automation. Re-engage in follow-up sequence.`;
} else {
  aiRecommendation = `❄️ COLD LEAD: Low conversion probability (Score: ${score}/100). Add to nurture list. Revisit in 60 days.`;
}

const conversionProbability = `${Math.round(score * 0.8)}%`;

return {
  json: {
    ...lead,
    leadScore: score,
    leadCategory,
    priority,
    urgency,
    buyingIntent,
    assignedTo,
    aiRecommendation,
    conversionProbability,
    qualificationStatus: score >= 30 ? 'Qualified' : 'Unqualified',
    pipelineStage: score >= 80 ? 'Hot Lead' : score >= 50 ? 'Qualified' : 'Lead Capture',
    dealValue: lead.budget,
    leadOwner: assignedTo,
    nextFollowUp: score >= 80 ? 'Immediate' : 'Day 1',
    followUpStatus: score >= 80 ? 'Escalated' : 'Scheduled'
  }
};

const leadStatus = $json.leadStatus || 'New Lead';
const inactiveStatuses = ['Won', 'Lost', 'Closed', 'Unqualified Rejected'];

if (inactiveStatuses.includes(leadStatus)) {
  return null;
}

return { json: $json };

