const inactiveStatuses = ['Won', 'Lost', 'Closed', 'Unqualified Rejected'];

if (inactiveStatuses.includes(leadStatus)) {
  return null;
}

return { json: $json };

const leadStatus = $json.leadStatus || 'New Lead';
const inactiveStatuses = ['Won', 'Lost', 'Closed', 'Unqualified Rejected'];

if (inactiveStatuses.includes(leadStatus)) {
  return null;
}

return { json: $json };

const leadStatus = $json.leadStatus || 'New Lead';
const inactiveStatuses = ['Won', 'Lost', 'Closed', 'Unqualified Rejected'];

if (inactiveStatuses.includes(leadStatus)) {
  return null;
}

return { json: $json };

const leads = $input.all().map(item => item.json);

const stats = {
  totalLeads: leads.length,
  hotLeads: leads.filter(l => l.leadCategory === 'Hot Lead').length,
  warmLeads: leads.filter(l => l.leadCategory === 'Warm Lead').length,
  coldLeads: leads.filter(l => l.leadCategory === 'Cold Lead').length,
  wonDeals: leads.filter(l => l.leadStatus === 'Won').length,
  lostDeals: leads.filter(l => l.leadStatus === 'Lost').length,
  activeLeads: leads.filter(l => ['New Lead', 'Contacted', 'Qualified'].includes(l.leadStatus)).length,
  conversionRate: (leads.filter(l => l.leadStatus === 'Won').length / leads.length * 100).toFixed(2),
  totalValue: leads.filter(l => l.leadStatus === 'Won').reduce((sum, l) => sum + (Number(l.dealValue) || 0), 0),
  avgScore: (leads.reduce((sum, l) => sum + (Number(l.leadScore) || 0), 0) / leads.length).toFixed(1)
};

const sources = {};
leads.forEach(l => {
  sources[l.source] = (sources[l.source] || 0) + 1;
});

const topSource = Object.entries(sources).sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A';

return [{
  json: {
    reportDate: new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
    ...stats,
    topLeadSource: topSource,
    sourceBreakdown: JSON.stringify(sources)
  }
}];
